 1→import { useCallback, useState } from 'react';
 2→import { isStringArray, storageGet, storageSet } from '../utils/storage';
 3→
 4→const STORAGE_KEY = 'recent-commands';
 5→const MAX_RECENT = 10;
 6→
 7→function loadRecent(): string[] {
 8→  return storageGet(STORAGE_KEY, isStringArray) ?? [];
 9→}
10→
11→export function useRecentCommands() {
12→  const [recentIds, setRecentIds] = useState<string[]>(loadRecent);
13→
14→  const addRecent = useCallback((id: string) => {
15→    setRecentIds(prev => {
16→      const next = [
17→        id,
18→        ...prev.filter(rid => rid !== id),
19→      ].slice(0, MAX_RECENT);
20→      storageSet(STORAGE_KEY, next);
21→      return next;
22→    });
23→  }, []);
24→
25→  const clearRecent = useCallback(() => {
26→    setRecentIds([]);
27→    storageSet(STORAGE_KEY, []);
28→  }, []);
29→
30→  return {
31→    recentIds,
32→    addRecent,
33→    clearRecent,
34→  };
35→}
