 263→      },
 264→      {
 265→        title: 'Types',
 266→        options: [
 267→          {
 268→            label: 'Commands',
 269→            value: 'commands',
 270→          },
 271→          {
 272→            label: 'Applications',
 273→            value: 'applications',
 274→          },
 275→        ],
 276→      },
 277→    ],
 278→    [],
