 301→    }
 302→
 303→    const result = query ? searchCommands(query) : sections;
 304→
 305→    const filteredResult = query
 306→      ? result
 307→          .map(s => {
 308→            if (filterValue === 'commands') {
 309→              return s.title === 'Suggestions' || s.title === 'Commands'
 310→                ? s
 311→                : {
 312→                    ...s,
 313→                    items: [],
 314→                  };
 315→            }
 316→            if (filterValue === 'applications') {
