 336→        item =>
 337→          fuzzyMatch(query, item.title) ||
 338→          fuzzyMatch(query, item.subtitle ?? ''),
 339→      );
 340→      if (filteredFavs.length > 0) {
 341→        const favIds = new Set(filteredFavs.map(f => f.id));
 342→        const dedupedSections = filteredResult
 343→          .map(s => ({
 344→            ...s,
 345→            items: s.items.filter(item => !favIds.has(item.id)),
 346→          }))
 347→          .filter(s => s.items.length > 0);
 348→        return [
 349→          {
 350→            title: 'Favorites',
 351→            items: filteredFavs,
 352→          },
 353→          ...dedupedSections,
 354→        ];
 355→      }
 356→      return filteredResult;
 357→    }
 358→
 359→    const pinnedSections: SectionData[] = [];
