 598→  const openSettings = useCallback(() => {
 599→    const settingsCmd = getCommand('settings');
 600→    if (settingsCmd) {
 601→      const isAlreadySettings =
 602→        currentNavData?.type === 'command' &&
 603→        currentNavData.commandId === 'settings';
