 1→const PREFIX = 'raycast-';
 2→
 3→function prefixKey(key: string): string {
 4→  return `${PREFIX}${key}`;
 5→}
 6→
 7→export function storageGet<T>(
 8→  key: string,
 9→  validate: (value: unknown) => value is T,
10→): T | null {
11→  try {
12→    const raw = localStorage.getItem(prefixKey(key));
13→    if (raw === null) return null;
14→    const parsed: unknown = JSON.parse(raw);
15→    return validate(parsed) ? parsed : null;
16→  } catch {
17→    return null;
18→  }
19→}
20→
21→export function storageSet<T>(key: string, value: T): void {
22→  try {
23→    localStorage.setItem(prefixKey(key), JSON.stringify(value));
24→  } catch {
25→    // localStorage unavailable
26→  }
27→}
28→
29→export function storageRemove(key: string): void {
30→  try {
31→    localStorage.removeItem(prefixKey(key));
32→  } catch {
33→    // localStorage unavailable
34→  }
35→}
36→
37→export function isStringArray(value: unknown): value is string[] {
38→  return Array.isArray(value) && value.every(v => typeof v === 'string');
39→}
40→
41→export function isString(value: unknown): value is string {
42→  return typeof value === 'string';
43→}
44→
45→export function isRecord(value: unknown): value is Record<string, unknown> {
46→  return typeof value === 'object' && value !== null && !Array.isArray(value);
47→}
48→
49→export function isBooleanRecord(
50→  value: unknown,
51→): value is Record<string, boolean> {
52→  if (!isRecord(value)) return false;
53→  return Object.values(value).every(v => typeof v === 'boolean');
54→}
