 1→import { useCallback, useMemo, useState } from 'react';
 2→import { isStringArray, storageGet, storageSet } from '../utils/storage';
 3→
 4→const STORAGE_KEY = 'favorites';
 5→
 6→function loadFavorites(): string[] {
 7→  return storageGet(STORAGE_KEY, isStringArray) ?? [];
 8→}
 9→
10→export function useFavorites() {
11→  const [favoriteIds, setFavoriteIds] = useState<string[]>(loadFavorites);
12→
13→  const favoriteSet = useMemo(() => new Set(favoriteIds), [favoriteIds]);
14→
15→  const isFavorite = useCallback(
16→    (id: string) => favoriteSet.has(id),
17→    [favoriteSet],
18→  );
19→
20→  const toggleFavorite = useCallback((id: string) => {
21→    setFavoriteIds(prev => {
22→      const next = prev.includes(id)
23→        ? prev.filter(fid => fid !== id)
24→        : [
25→            ...prev,
26→            id,
27→          ];
28→      storageSet(STORAGE_KEY, next);
29→      return next;
30→    });
31→  }, []);
32→
33→  const moveFavorite = useCallback((id: string, direction: 'up' | 'down') => {
34→    setFavoriteIds(prev => {
35→      const idx = prev.indexOf(id);
36→      if (idx === -1) return prev;
37→      const targetIdx = direction === 'up' ? idx - 1 : idx + 1;
38→      if (targetIdx < 0 || targetIdx >= prev.length) return prev;
39→      const next = [...prev];
40→      next[idx] = prev[targetIdx]!;
41→      next[targetIdx] = prev[idx]!;
42→      storageSet(STORAGE_KEY, next);
43→      return next;
44→    });
45→  }, []);
46→
47→  return {
48→    favoriteIds,
49→    isFavorite,
50→    toggleFavorite,
51→    moveFavorite,
52→  };
53→}
